// require modules
const express = require('express');
const { Pool } = require('pg');

// set up Postgres connection
const dbPool = new Pool({
    user: 'postgres',
    host: 'localhost',
    database: 'mydatabase',
    password: 'mypassword',
    port: 5432,
});

// create a table
function createTable(tableName, columns) {
    const query = `
        CREATE TABLE IF NOT EXISTS ${tableName} (
            ${columns.map(column => `${column.name} ${column.type}`).join(', ')}
        );
    `;
    dbPool.query(query)
        .then(() => console.log(`Table created: ${tableName}`))
        .catch(err => console.error('Error creating table:', err));
}

// insert data into table
function insertData(tableName, data) {
    const query = `
        INSERT INTO ${tableName} (${Object.keys(data).join(', ')})
        VALUES (${Object.values(data).map(value => `'${value}'`).join(', ')});
    `;
    dbPool.query(query)
        .then(() => console.log(`Data inserted into table: ${tableName}`))
        .catch(err => console.error('Error inserting data:', err));
}

// select data from table
function selectData(tableName, columns = '*') {
    const query = `
        SELECT ${columns} FROM ${tableName};
    `;
    dbPool.query(query)
        .then(res => console.log(`Data selected from table: ${tableName}`, res.rows))
        .catch(err => console.error('Error selecting data:', err));
}

// update data in table
function updateData(tableName, data) {
    const query = `
        UPDATE ${tableName}
        SET ${Object.keys(data).map(key => `${key} = '${data[key]}'`).join(', ')}
        RETURNING *;
    `;
    dbPool.query(query)
        .then(res => console.log(`Data updated in table: ${tableName}`, res.rows))
        .catch(err => console.error('Error updating data:', err));
}

// delete data from table
function deleteData(tableName, condition) {
    const query = `
        DELETE FROM ${tableName}
        WHERE ${condition};
    `;
    dbPool.query(query)
        .then(() => console.log(`Data deleted from table: ${tableName}`))
        .catch(err => console.error('Error deleting data:', err));
}

// test CRUD operations
createTable('users', [
    { name: 'id', type: 'SERIAL PRIMARY KEY' },
    { name: 'name', type: 'VARCHAR(255)' },
]);
insertData('users', { id: 1, name: 'John Doe' });
selectData('users');
updateData('users', { id: 1, name: 'Jane Doe' });
deleteData('users', 'id = 1');

// set up Express server
const app = express();

app.listen(3000, () => {
    console.log('Server listening on port 3000');
});